#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int size = 2*N;
        int *arr = (int*)malloc(size*sizeof(int));
        for(int i=0;i<size;i++) scanf("%d", &arr[i]);
        char *vis = (char*)calloc(N+1, sizeof(char));
        int printed = 0;
        for(int i=0;i<size;i++){
            int x = arr[i];
            if(!vis[x]){
                if(printed) printf(" ");
                printf("%d", x);
                vis[x] = 1;
                printed++;
            }
        }
        printf("\n");
        free(arr);
        free(vis);
    }
    return 0;
}

