#!/usr/bin/env python3
import sys
def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        arr = [next(it) for _ in range(2*N)]
        seen = [False]*(N+1)
        perm = []
        for x in arr:
            if not seen[x]:
                perm.append(str(x))
                seen[x] = True
        out_lines.append(' '.join(perm))
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

