const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let output = [];
for (let t = 0; t < T; t++) {
  const N = data[idx++];
  const total = 2 * N;
  const arr = data.slice(idx, idx + total);
  idx += total;
  const seen = new Array(N + 1).fill(false);
  const perm = [];
  for (const x of arr) {
    if (!seen[x]) {
      perm.push(x);
      seen[x] = true;
    }
  }
  output.push(perm.join(' '));
}
